// Backfill: traduz titulo e resumo das noticias de fontes em ingles para PT.
// Defensivo: sem helpers ou erro -> mantem original. Detecta idioma e pula o que
// ja esta em PT. Ritmo controlado para nao estourar o tradutor gratis.
const _helpers = (this && this.helpers) ? this.helpers : null;

async function trad(texto) {
  const t = String(texto || '').trim();
  if (!t || !_helpers || !_helpers.httpRequest) return { out: texto, lang: null };
  try {
    const url = 'https://translate.googleapis.com/translate_a/single?client=gtx&sl=auto&tl=pt&dt=t&q=' + encodeURIComponent(t.slice(0, 1500));
    const r = await _helpers.httpRequest({ url, json: true });
    const lang = Array.isArray(r) ? r[2] : null;
    if (lang === 'pt') return { out: texto, lang };
    const segs = (Array.isArray(r) && Array.isArray(r[0])) ? r[0] : [];
    const o = segs.map((s) => (Array.isArray(s) ? s[0] : '')).join('').trim();
    return { out: o || texto, lang };
  } catch (e) {
    return { out: texto, lang: null };
  }
}

let rows = $input.all().map((i) => i.json);
if (rows.length === 1 && Array.isArray(rows[0])) rows = rows[0];

const out = [];
let traduzidos = 0;
for (const row of rows) {
  if (!row || !row.id) continue;
  const tt = await trad(row.titulo);
  let rr = { out: row.resumo || null };
  if (row.resumo) rr = await trad(row.resumo);
  const novoTitulo = (tt.out || '').slice(0, 300) || row.titulo;
  if (novoTitulo !== row.titulo) traduzidos++;
  out.push({ json: { id: row.id, titulo: novoTitulo, resumo: rr.out || null } });
  await new Promise((r) => setTimeout(r, 120));
}
console.log('Backfill: ' + out.length + ' itens, ' + traduzidos + ' com titulo alterado');
return out;
